        pipe_.InitBuffer(aRowQ_, ARBUF_NUM, tileK_ * sizeof(float));
        pipe_.InitBuffer(cRowQ_, CBUF_NUM, tileN_ * sizeof(float));
        pipe_.InitBuffer(tmpQ_,  TBUF_NUM, tileN_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
